sql:
SELECT earnings, points_earned
FROM golfer_tournament_performance
WHERE golfer_id = 0 AND tournament_id = 0;

external_knowledge:
- 'par-fect' golfers refer to golfers with the lowest average strokes per round in the tournament, as it signifies their ability to achieve the lowest score (par) per round; 
- The Masters Tournament is an annual golf tournament held at Augusta National Golf Club; 
- A lower average strokes per round is indicative of a better golfer.

sql:
SELECT golfer_name
FROM golfers
WHERE country = 'United States';

SELECT career_wins
FROM golfers
WHERE golfer_id = 0;

SELECT COUNT(tournament_id) AS total_tournaments_played
FROM golfer_tournament_performance
WHERE golfer_id = 1;
